SELECT *
FROM cotton_varieties
WHERE lint_yield > (SELECT AVG(lint_yield) FROM cotton_varieties);

SELECT COUNT(*) 
FROM cotton_data 
WHERE variety_id = (SELECT variety_id FROM cotton_varieties WHERE variety_name = 'NG 4936 B3XF');

SELECT * 
FROM cotton_data 
WHERE field_id IN (SELECT field_id FROM cotton_data WHERE variety_id = 1);

SELECT *
FROM cotton_varieties
LIMIT 10;

SELECT soil_type, AVG(field_size) AS average_size
FROM cotton_fields
GROUP BY soil_type;

SELECT *
FROM cotton_varieties
WHERE lint_yield > (
    SELECT AVG(lint_yield)
    FROM (
        SELECT lint_yield
        FROM cotton_varieties
        WHERE lint_yield = (
            SELECT MAX(lint_yield) FROM cotton_varieties
        )
    ) AS high_yield_varieties
);

SELECT AVG(lint_yield) AS average_lint_yield
FROM cotton_data
WHERE variety_id = 0 AND field_id = 1;

SELECT cv.variety_name, cv.lint_yield, cv.staple_length
FROM cotton_varieties cv
WHERE cv.staple_length > (
  SELECT AVG(cv2.staple_length) 
  FROM cotton_varieties cv2
);

SELECT variety_id, variety_name, lint_yield 
FROM cotton_varieties 
WHERE lint_yield = (SELECT MAX(lint_yield) FROM cotton_varieties);

SELECT field_name, location
FROM cotton_fields
ORDER BY field_size DESC;

SELECT variety_id, AVG(lint_yield) AS avg_lint_yield
FROM cotton_data
GROUP BY variety_id;

SELECT cv.variety_id, parent_varieties.variety_name
FROM cotton_varieties cv
JOIN cotton_varieties AS parent_varieties ON cv.parent_variety_id = parent_varieties.variety_id;

SELECT cv.variety_name, cd.lint_yield 
FROM cotton_varieties cv 
JOIN cotton_data cd ON cv.variety_id = cd.variety_id;
